<?php
namespace App\Models;
use App\Config\Database; use PDO;
final class Repository {private PDO $db; public function __construct(){ $this->db=Database::connection();} public function db():PDO{return $this->db;} public function all(string $table,string $order='id DESC'):array{$allowed=['roles','usuarios','generos','artistas','bandas','albumes','canciones','locales','eventos','planes'];if(!in_array($table,$allowed,true))throw new \InvalidArgumentException();return $this->db->query("SELECT * FROM `$table` ORDER BY $order")->fetchAll();} public function find(string $table,int $id):?array{$s=$this->db->prepare("SELECT * FROM `$table` WHERE id=?");$s->execute([$id]);return $s->fetch()?:null;} public function save(string $table,array $data,?int $id=null):int{$cols=array_keys($data);if($id){$set=implode(',',array_map(fn($c)=>"`$c`=?",$cols));$s=$this->db->prepare("UPDATE `$table` SET $set WHERE id=?");$s->execute([...array_values($data),$id]);return $id;} $names=implode(',',array_map(fn($c)=>"`$c`",$cols));$q=implode(',',array_fill(0,count($cols),'?'));$s=$this->db->prepare("INSERT INTO `$table` ($names) VALUES ($q)");$s->execute(array_values($data));return(int)$this->db->lastInsertId();} public function disable(string $table,int $id):void{$s=$this->db->prepare("UPDATE `$table` SET estado=IF(estado=1,0,1) WHERE id=?");$s->execute([$id]);}}
